import collections

class Solution:
    def predictPartyVictory(self, senate: str) -> str:
        n = len(senate)

        radiant_q = collections.deque()
        dire_q = collections.deque()

        # Populate queues with initial indices of senators
        for i, senator in enumerate(senate):
            if senator == 'R':
                radiant_q.append(i)
            else:
                dire_q.append(i)

        # Simulate rounds
        while radiant_q and dire_q:
            r_idx = radiant_q.popleft()
            d_idx = dire_q.popleft()

            if r_idx < d_idx:
                # Radiant senator bans Dire, Radiant senator gets to participate in the next round
                radiant_q.append(r_idx + n)
            else:
                # Dire senator bans Radiant, Dire senator gets to participate in the next round
                dire_q.append(d_idx + n)

        # Determine the winner
        if radiant_q:
            return "Radiant"
        else:
            return "Dire"
